body:
This MLIR
```
module attributes {circt.loweringOptions = "locationInfoStyle=none,disallowPackedStructAssignments"} {
    hw.module @Foo(%I: !hw.struct<x: i8, y: i1>, %S: i1) -> (O: !hw.struct<x: i8, y: i1>) {
        %0 = hw.struct_extract %I["x"] : !hw.struct<x: i8, y: i1>
        %2 = hw.constant -1 : i8
        %1 = comb.xor %2, %0 : i8
        %3 = hw.struct_extract %I["y"] : !hw.struct<x: i8, y: i1>
        %5 = hw.constant -1 : i1
        %4 = comb.xor %5, %3 : i1
        %6 = hw.struct_create (%1, %4) : !hw.struct<x: i8, y: i1>
        hw.output %6 : !hw.struct<x: i8, y: i1>
    }
}
```
correctly produces:
```
// Generated by CIRCT firtool-1.48.0-34-g7018fb13b
module Foo(
  input  struct packed {logic [7:0] x; logic y; } I,
  input                                           S,
  output struct packed {logic [7:0] x; logic y; } O
);

  wire struct packed {logic [7:0] x; logic y; } _GEN;
  assign _GEN.x = ~I.x;
  assign _GEN.y = ~I.y;
  assign O = _GEN;
endmodule

```

However this MLIR
```
module attributes {circt.loweringOptions = "locationInfoStyle=none,disallowPackedStructAssignments"} {
    hw.module @Foo(%I: !hw.struct<x: i8, y: i1>, %S: i1) -> (O: !hw.struct<x: i8, y: i1>) {
        %0 = hw.constant 190 : i8
        %1 = hw.constant 1 : i1
        %2 = hw.struct_create (%0, %1) : !hw.struct<x: i8, y: i1>
        hw.output %2 : !hw.struct<x: i8, y: i1>
    }
}
```
creates a packed assignment
```
// Generated by CIRCT firtool-1.48.0-34-g7018fb13b
module Foo(
  input  struct packed {logic [7:0] x; logic y; } I,
  input                                           S,
  output struct packed {logic [7:0] x; logic y; } O
);

  assign O = '{x: 8'hBE, y: 1'h1};
endmodule

```
